// Look back a wide window every run (15 min). Per-job dedupe happens in
// 'Filter terminal + unsent' downstream — widening the window can't
// produce duplicate Slack cards. This avoids the race where a job's
// completed_at lands between two watcher ticks and slides off the
// since-marker forever.
const since = new Date(Date.now() - 15 * 60 * 1000).toISOString();
return [{ json: { since } }];

// Per-job dedupe: each terminal-state notification fires exactly once
// per job_id. Tracks notified IDs in workflow staticData with TTL
// pruning to keep memory bounded.
const staticData = $getWorkflowStaticData('global');
const notified = staticData.notifiedJobIds || {};   // { job_id: notified_iso }
const TTL_HOURS = 6;
const cutoff = Date.now() - TTL_HOURS * 60 * 60 * 1000;

for (const k of Object.keys(notified)) {
  if (new Date(notified[k]).getTime() < cutoff) delete notified[k];
}

const out = [];
for (const item of items) {
  const job = item.json || {};
  if (!job || !job.id) continue;
  if (job.status !== 'completed' && job.status !== 'failed') continue;  // skip queued/running
  if (notified[job.id]) continue;
  notified[job.id] = new Date().toISOString();
  out.push({ json: job });
}

staticData.notifiedJobIds = notified;
return out;

const ctx = $json;
const rfp = ctx.rfp || {};
const screening = ctx.screening || {};
const job = $('Filter terminal + unsent').item.json;
const draftId = job && job.draft_id;

const sourceType = rfp.source_type || 'unknown';
const meta = rfp.source_metadata || {};
const sender = meta.from || meta.notice_id || meta.filename || meta.url || '';
const received = rfp.received_at ? new Date(rfp.received_at).toLocaleString() : '';
const breadcrumb = sourceType === 'email'
  ? `Source: email from ${sender} (received ${received})`
  : sourceType === 'sam_gov'
    ? `Source: SAM.gov notice ${meta.notice_id || rfp.external_id || ''} (received ${received})`
    : `Source: ${sourceType} ${sender} (received ${received})`;

const uiUrl = $env.KAIZEN_UI_URL || 'http://localhost:8501';
const reviewUrl = draftId ? `${uiUrl}/?draft=${draftId}` : `${uiUrl}/?rfp=${rfp.id}`;
const exportUrl = draftId ? `http://localhost:8000/draft/${draftId}/export` : null;

const payload = {
  text: `:memo: Draft ready — ${rfp.title || '(no title)'}`,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: `:memo: Draft ready — ${rfp.title || '(no title)'}`.slice(0, 150), emoji: true } },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Agency*\n${rfp.agency || '—'}` },
        { type: 'mrkdwn', text: `*Fit score*\n${screening.fit_score ?? '—'}` },
        { type: 'mrkdwn', text: `*Recommendation*\n${screening.recommendation || '—'}` },
        { type: 'mrkdwn', text: `*Draft id*\n\`${draftId || '(unknown)'}\`` }
      ]
    },
    { type: 'context', elements: [{ type: 'mrkdwn', text: breadcrumb }] },
    {
      type: 'actions',
      elements: [
        { type: 'button', text: { type: 'plain_text', text: 'Open in dashboard' }, url: reviewUrl, style: 'primary' },
        ...(exportUrl ? [{ type: 'button', text: { type: 'plain_text', text: 'Download .md' }, url: exportUrl }] : [])
      ]
    }
  ]
};
return [{ json: payload }];

const ctx = $json;
const rfp = ctx.rfp || {};
const screening = ctx.screening || {};
const job = $('Filter terminal + unsent').item.json;
const err = (job && job.error_message) || '(no error message recorded)';
const errShort = err.length > 240 ? err.slice(0, 240) + '…' : err;

const sourceType = rfp.source_type || 'unknown';
const meta = rfp.source_metadata || {};
const sender = meta.from || meta.notice_id || meta.filename || meta.url || '';
const received = rfp.received_at ? new Date(rfp.received_at).toLocaleString() : '';
const breadcrumb = sourceType === 'email'
  ? `Source: email from ${sender} (received ${received})`
  : sourceType === 'sam_gov'
    ? `Source: SAM.gov notice ${meta.notice_id || rfp.external_id || ''} (received ${received})`
    : `Source: ${sourceType} ${sender} (received ${received})`;

const uiUrl = $env.KAIZEN_UI_URL || 'http://localhost:8501';
const rfpUrl = `${uiUrl}/?rfp=${rfp.id}`;

const payload = {
  text: `:warning: Draft generation failed — ${rfp.title || '(no title)'}`,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: `:warning: Draft failed — ${rfp.title || '(no title)'}`.slice(0, 150), emoji: true } },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Agency*\n${rfp.agency || '—'}` },
        { type: 'mrkdwn', text: `*Fit score*\n${screening.fit_score ?? '—'}` },
        { type: 'mrkdwn', text: `*Job id*\n\`${(job && job.id) || '?'}\`` },
        { type: 'mrkdwn', text: `*Status*\nfailed` }
      ]
    },
    { type: 'section', text: { type: 'mrkdwn', text: `*Error*\n\`${errShort}\`` } },
    { type: 'context', elements: [{ type: 'mrkdwn', text: breadcrumb }] },
    {
      type: 'actions',
      elements: [
        { type: 'button', text: { type: 'plain_text', text: 'Open RFP' }, url: rfpUrl, style: 'primary' }
      ]
    }
  ]
};
return [{ json: payload }];
